var allParts = [];
window.applyFilters = function () {
  var typeVal = (document.getElementById('filter_type') || {}).value || '';
  var modelVal = ((document.getElementById('filter_model') || {}).value || '').toLowerCase().trim();
  var filtered = allParts.filter(function (p) {
    var typeMatch = !typeVal || p.part_type === typeVal;
    var modelMatch = !modelVal || [p.donor_make, p.donor_model].filter(Boolean).join(' ').toLowerCase().indexOf(modelVal) !== -1;
    return typeMatch && modelMatch;
  });
  var stock = filtered.filter(function (r) {
    return r.availability === 'in_stock';
  });
  var donor = filtered.filter(function (r) {
    return r.availability === 'in_donor_asset';
  });
  var count = document.getElementById('count');
  var tbody = document.getElementById('table_body');
  if (!tbody) return;
  if (count) count.textContent = filtered.length + ' part' + (filtered.length !== 1 ? 's' : '');
  if (!filtered.length) {
    tbody.innerHTML = '<tr><td colspan="8" class="empty">No parts available</td></tr>';
    return;
  }
  var html = '';
  if (stock.length) {
    html += '<tr class="group-row"><td colspan="8">✅ In Stock (' + stock.length + ')</td></tr>';
    html += stock.map(function (r, i) {
      var mm = [r.donor_make, r.donor_model].filter(Boolean).join(' · ') || '—';
      var bat = r.is_battery ? ' 🔋' : '';
      return '<tr><td><span class="badge badge-stock">Stock</span></td>' + '<td><span class="part-type">' + (r.part_type || '—') + bat + '</span></td>' + '<td><span class="asset-ref">' + (r.donor_asset_ref || '—') + '</span></td>' + '<td>' + mm + '</td>' + '<td style="font-family:monospace;font-size:11px">' + (r.serial_number || '—') + '</td>' + '<td>' + (r.condition_grade ? '<span class="grade">' + r.condition_grade + '</span>' : '—') + '</td>' + '<td>' + (r.part_cost ? '£' + Number(r.part_cost).toFixed(2) : '—') + '</td>' + '<td><button class="btn-install" onclick="window.installPart(' + i + ',\'stock\')">Install</button></td></tr>';
    }).join('');
  }
  if (donor.length) {
    html += '<tr class="group-row"><td colspan="8">📦 From Donor Asset (' + donor.length + ')</td></tr>';
    html += donor.map(function (r, i) {
      var mm = [r.donor_make, r.donor_model].filter(Boolean).join(' · ') || '—';
      var bat = r.is_battery ? ' 🔋' : '';
      return '<tr><td><span class="badge badge-donor">Donor</span></td>' + '<td><span class="part-type">' + (r.part_type || '—') + bat + '</span></td>' + '<td><span class="asset-ref">' + (r.donor_asset_ref || '—') + '</span></td>' + '<td>' + mm + '</td><td>—</td><td>—</td><td>—</td>' + '<td><button class="btn-install donor" onclick="window.installPart(' + i + ',\'donor\')">Pull & Install</button></td></tr>';
    }).join('');
  }
  tbody.innerHTML = html;
};
window.installPart = function (idx, type) {
  var parts = allParts.filter(function (r) {
    return r.availability === (type === 'stock' ? 'in_stock' : 'in_donor_asset');
  });
  var row = parts[idx];
  if (!row) return;
  appsmith.updateModel({
    selectedPart: row
  });
  appsmith.triggerEvent('onInstallPart');
};
function render(model) {
  allParts = model.parts || [];
  var select = document.getElementById('filter_type');
  if (select) {
    var current = select.value;
    var types = [];
    allParts.forEach(function (p) {
      if (p.part_type && types.indexOf(p.part_type) === -1) types.push(p.part_type);
    });
    types.sort();
    select.innerHTML = '<option value="">All part types</option>' + types.map(function (t) {
      return '<option value="' + t + '"' + (t === current ? ' selected' : '') + '>' + t + '</option>';
    }).join('');
  }
  window.applyFilters();
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

